const body = $input.first().json.body || $input.first().json;
const jd = body.jd;

if (!jd || typeof jd !== 'string' || jd.trim().length === 0) {
  throw new Error('Missing or empty jd field in request body');
}

// reset retry counter on each fresh request
$workflow.staticData.retryCount = 0;
$workflow.staticData.pageRetryCount = 0;

return [{ json: { jd: jd.trim() } }];

const binaryData = $input.first().binary.data;
const jsonStr = Buffer.from(binaryData.data, 'base64').toString('utf-8');
const resume = JSON.parse(jsonStr);
const jd = $('Validate Input').first().json.jd;
return [{ json: { resume, jd } }];

const binaryData = $input.first().binary.data;
const prompt = Buffer.from(binaryData.data, 'base64').toString('utf-8');
const jd = $('Parse Resume JSON').first().json.jd;
return [{ json: { extractPrompt: prompt, jd } }];

const resp = $input.first().json;
const text = resp.content[0].text.trim();
let meta;
try {
  const match = text.match(/\{[\s\S]*\}/);
  meta = JSON.parse(match ? match[0] : text);
} catch(e) {
  throw new Error('Metadata extraction returned invalid JSON: ' + text);
}
const resume = $('Parse Resume JSON').first().json.resume;
const jd = $('Parse Resume JSON').first().json.jd;
return [{ json: { meta, resume, jd } }];

const binaryData = $input.first().binary.data;
const systemPrompt = Buffer.from(binaryData.data, 'base64').toString('utf-8');
const { meta, resume, jd } = $('Parse Metadata').first().json;
const retryReason = $workflow.staticData.retryReason || null;

let userMsg = `MASTER RESUME:\n${JSON.stringify(resume, null, 2)}\n\nJOB DESCRIPTION:\n${jd}`;
if (retryReason) {
  userMsg += `\n\nREVISION REQUIRED: ${retryReason}`;
}

return [{ json: { systemPrompt, userMsg, meta, resume, jd } }];

const resp = $input.first().json;
const text = resp.content[0].text.trim();

let tailored;
try {
  const match = text.match(/\{[\s\S]*\}/);
  tailored = JSON.parse(match ? match[0] : text);
} catch(e) {
  throw new Error('Tailoring returned invalid JSON: ' + text.substring(0, 200));
}

const SUMMARY_LIMIT = 280;
const BULLET_CEIL = 220;
const BULLET_FLOOR = 150;
const PROJECT_DESC_LIMIT = 180;

const errors = [];

if (!tailored.summary || tailored.summary.length > SUMMARY_LIMIT) {
  errors.push(`Summary exceeds ${SUMMARY_LIMIT} chars (got ${tailored.summary?.length})`);
}

if (!Array.isArray(tailored.tech_stack) || tailored.tech_stack.length < 8 || tailored.tech_stack.length > 12) {
  errors.push(`tech_stack must have 8-12 items (got ${tailored.tech_stack?.length})`);
}

for (const job of (tailored.experience || [])) {
  for (const bullet of (job.bullets || [])) {
    if (bullet.length > BULLET_CEIL) {
      errors.push(`Bullet exceeds ${BULLET_CEIL} chars in ${job.company}: "${bullet.substring(0, 60)}..."`);
    } else if (bullet.length < BULLET_FLOOR) {
      errors.push(`Bullet under ${BULLET_FLOOR} chars in ${job.company}: "${bullet.substring(0, 60)}..."`);
    }
  }
}

for (const proj of (tailored.projects || [])) {
  if (proj.description && proj.description.length > PROJECT_DESC_LIMIT) {
    errors.push(`Project "${proj.name}" description exceeds ${PROJECT_DESC_LIMIT} chars`);
  }
}

if (tailored.projects && tailored.projects.length > 2) {
  tailored.projects = tailored.projects.slice(0, 2);
}

const retryCount = $workflow.staticData.retryCount || 0;
const needsRetry = errors.length > 0;

if (needsRetry) {
  $workflow.staticData.retryReason = `Previous response exceeded length limits. Issues: ${errors.join('; ')}. Compress while preserving all hard numbers and tools. Stay within the bullet formula (150-220 chars).`;
}

return [{ json: { tailored, needsRetry, retryCount, errors } }];

// increment retry counter and loop back
$workflow.staticData.retryCount = ($workflow.staticData.retryCount || 0) + 1;
const { tailored, errors } = $input.first().json;
return [{ json: { tailored, errors, retryCount: $workflow.staticData.retryCount } }];

const { tailored } = $input.first().json;

const resume = $('Parse Resume JSON').first().json.resume;

// Build experience HTML
let expHtml = '';
for (const job of tailored.experience) {
  const bullets = (job.bullets || []).map(b => `<li>${b}</li>`).join('\n        ');
  expHtml += `
  <div class="job">
    <div class="job-header">
      <div>
        <span class="job-title">${job.title}</span> &mdash;
        <span class="job-company">${job.company}</span>
        <span class="job-location">&nbsp;·&nbsp;${job.location}</span>
      </div>
      <div class="job-dates">${job.start} – ${job.end}</div>
    </div>
    <ul class="bullets">
        ${bullets}
    </ul>
  </div>`;
}

// Build projects HTML
let projHtml = '';
for (const proj of (tailored.projects || []).slice(0, 2)) {
  projHtml += `
  <div class="project">
    <span class="project-name">${proj.name}</span>
    <span class="project-desc"> — ${proj.description}</span>
  </div>`;
}

// Education (static from master)
let eduHtml = '';
for (const edu of resume.education) {
  eduHtml += `
  <div class="edu-row">
    <div>
      <div class="edu-school">${edu.school}</div>
      <div class="edu-degree">${edu.degree}</div>
    </div>
    <div class="edu-meta">${edu.date}<br>GPA: ${edu.gpa}</div>
  </div>`;
}

return [{ json: { tailored, expHtml, projHtml, eduHtml } }];

const binaryData = $input.first().binary.data;
let html = Buffer.from(binaryData.data, 'base64').toString('utf-8');

const resume = $('Parse Resume JSON').first().json.resume;
const { tailored, expHtml, projHtml, eduHtml } = $('Build HTML Parts').first().json;

html = html.replace('{{name}}', resume.name);
html = html.replace('{{email}}', resume.contact.email);
html = html.replace('{{phone}}', resume.contact.phone);
html = html.replace('{{location}}', resume.contact.location);
html = html.replace('{{linkedin}}', resume.contact.linkedin);
html = html.replace('{{github}}', resume.contact.github);
html = html.replace('{{summary}}', tailored.summary);
html = html.replace('{{tech_stack}}', tailored.tech_stack.join(' · '));
html = html.replace('{{experience}}', expHtml);
html = html.replace('{{projects}}', projHtml);
html = html.replace('{{education}}', eduHtml);

return [{ json: { renderedHtml: html, tailored } }];

// Convert rendered HTML string to binary so it can be sent as a file
const { renderedHtml, tailored } = $('Render HTML').first().json;

const buf = Buffer.from(renderedHtml, 'utf-8');
const base64 = buf.toString('base64');

return [{
  json: { tailored },
  binary: {
    renderedHtmlFile: {
      data: base64,
      mimeType: 'text/html',
      fileName: 'resume.html'
    }
  }
}];

// Use pdf-lib to count pages
const { PDFDocument } = require('pdf-lib');

const pdfBinary = $input.first().binary.pdfData;
if (!pdfBinary) throw new Error('No PDF received from Gotenberg');

const pdfBytes = Buffer.from(pdfBinary.data, 'base64');
const pdfDoc = await PDFDocument.load(pdfBytes);
const pageCount = pdfDoc.getPageCount();

const tailored = $('Build HTML Parts').first().json.tailored;
const pageRetryCount = $workflow.staticData.pageRetryCount || 0;
const tooLong = pageCount > 1;

if (tooLong) {
  $workflow.staticData.retryReason = `Resume rendered as ${pageCount} pages instead of 1. Aggressively compress all bullet points to 150-170 chars each. Reduce summary to under 220 chars. Keep only the 8 most relevant tech stack items.`;
  $workflow.staticData.retryCount = 0;
}

return [{ json: { pageCount, tooLong, pageRetryCount, tailored, pdfBase64: pdfBinary.data } }];

const { tailored, pdfBase64 } = $input.first().json;

const company = (tailored.company || 'Company').replace(/[^a-zA-Z0-9]/g, '_');
const role = (tailored.role || 'Role').replace(/[^a-zA-Z0-9]/g, '_');
const filename = `Sridhar_Resume_${company}_${role}.pdf`;
const outputPath = `/data/output/${filename}`;

return [{
  json: { outputPath, filename, tailored, pdfBase64 },
  binary: {
    pdfFile: {
      data: pdfBase64,
      mimeType: 'application/pdf',
      fileName: filename
    }
  }
}];
